import{_ as o,o as t,c as a,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Architecture","description":"","frontmatter":{"docSection":"architecture-security","docType":"reference","audiences":["operator","app-developer","contributor"]},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),i={name:"architecture.md"};function r(n,e,d,c,l,p){return t(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><p>A contributor-oriented summary of how Sovereign fits together. It distils the platform architecture into public documentation. For building plugins see <a href="./plugin-development.html">plugin-development.md</a>; for running an instance see <a href="./self-hosting.html">self-hosting.md</a>.</p><h2 id="what-sovereign-is" tabindex="-1">What Sovereign is <a class="header-anchor" href="#what-sovereign-is" aria-label="Permalink to &quot;What Sovereign is&quot;">​</a></h2><p>A modular, self-hostable workspace runtime. A shared platform — auth, database, email, UI — hosts installable <strong>plugins</strong> as first-class apps. The plugin system <em>is</em> the product. v1 is single-tenant, multi-user, privacy-first.</p><h2 id="deployment-model-srs-§3-1" tabindex="-1">Deployment model (SRS §3.1) <a class="header-anchor" href="#deployment-model-srs-§3-1" aria-label="Permalink to &quot;Deployment model (SRS §3.1)&quot;">​</a></h2><p>Two Next.js apps behind one public entry point:</p><ul><li><strong>runtime</strong> (<code>runtime/</code>) — the platform shell, middleware, plugin host, and SDK bridge. The only publicly-exposed service.</li><li><strong>auth</strong> (<code>apps/auth/</code>) — a self-contained better-auth server owning the identity database and login UI. Not mapped to a public port; reached over the internal network (and behind one reverse proxy in production, so the session cookie is shared by host).</li></ul><p>Docker Compose is the canonical deployment. Production images build from Next.js standalone output. A PM2-based non-Docker path is also supported (RFC 0026, <code>sv setup pm2</code>).</p><h2 id="layer-overview-srs-§3-2" tabindex="-1">Layer overview (SRS §3.2) <a class="header-anchor" href="#layer-overview-srs-§3-2" aria-label="Permalink to &quot;Layer overview (SRS §3.2)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser → runtime (shell, middleware, plugins)</span></span>
<span class="line"><span>              │  sdk.auth · sdk.db · sdk.mailer · sdk.platform</span></span>
<span class="line"><span>              ├─ auth server (better-auth)         identity</span></span>
<span class="line"><span>              ├─ Drizzle DB (SQLite | Postgres)    platform + plugin data</span></span>
<span class="line"><span>              └─ mailer (SMTP)                      email</span></span></code></pre></div><h2 id="auth-srs-§3-3-§3-10-auth-05-06" tabindex="-1">Auth (SRS §3.3, §3.10; AUTH-05/06) <a class="header-anchor" href="#auth-srs-§3-3-§3-10-auth-05-06" aria-label="Permalink to &quot;Auth (SRS §3.3, §3.10; AUTH-05/06)&quot;">​</a></h2><p>better-auth manages sessions via an httpOnly, host-scoped cookie. The runtime middleware verifies each request <strong>locally</strong> from better-auth&#39;s signed <code>session_data</code> cookie cache (HMAC with the shared <code>AUTH_SECRET</code>), avoiding a round-trip per request; it falls back to the auth server&#39;s <code>/api/verify</code> when no cache cookie is present, forwarding the refreshed cookie so the cache self-heals. The first registered user becomes <code>platform:owner</code>; subsequent users become <code>platform:user</code>.</p><p><strong>MFA (RFC 0012):</strong> better-auth&#39;s <code>twoFactor</code> plugin handles TOTP (authenticator app + 10 backup codes) and <code>@better-auth/passkey</code> handles WebAuthn passkeys. Both are opt-in per user; passkeys also work as a passwordless login path. The Account plugin&#39;s Security tab manages enrollment; Console → Users provides an admin &quot;Reset MFA&quot; action, and <code>sv user reset-mfa &lt;email&gt;</code> is the CLI break-glass for SQLite instances.</p><h2 id="runtime-srs-§3-4" tabindex="-1">Runtime (SRS §3.4) <a class="header-anchor" href="#runtime-srs-§3-4" aria-label="Permalink to &quot;Runtime (SRS §3.4)&quot;">​</a></h2><p>The middleware is the gate: it authenticates the request, injects the verified user as <code>x-sovereign-user-*</code> headers for downstream server components, enforces <code>adminOnly</code> (403), disabled-plugin (404), and paywalled-plugin (303/402) rules, and serves the configured root plugin at <code>/</code>. Plugin routes are composed into the App Router at build time.</p><p><strong>Capabilities</strong> flow from two sources: platform-role presets (11 built-in capabilities derived from the user&#39;s role, RFC 0021) and plugin-declared capabilities with <code>defaultGrant: &quot;all&quot;</code> (injected from the generated <code>plugin-capabilities.ts</code>, RFC 0022). Both are serialised into the <code>x-sovereign-user-capabilities</code> header so <code>sdk.auth.hasCapability</code> can resolve them synchronously in any server component or route handler without a DB call.</p><p><strong>Platform roles (RFC 0021):</strong> four presets — <code>platform:owner</code> (full, including <code>role:assign</code>), <code>platform:admin</code> (full except role assignment), <code>platform:auditor</code> (read-only Console), <code>platform:user</code> (basic access). The first user becomes owner; existing admin-only instances are migrated on first startup.</p><p><strong>Production dev-mode (RFC 0020):</strong> when <code>SOVEREIGN_DEV_MODE_ENABLED=true</code>, a request carrying the correct <code>X-Sovereign-Dev-Mode-Secret</code> header routes SDK DB calls to a mock database for that request only — real requests run unaffected. The response is stamped with <code>x-sovereign-dev-mode: active</code>. A structured logger (<code>LOG_LEVEL</code>) writes newline-delimited JSON to stdout.</p><h2 id="plugin-system-manifest-srs-§3-5-§3-8-§3-9" tabindex="-1">Plugin system &amp; manifest (SRS §3.5, §3.8, §3.9) <a class="header-anchor" href="#plugin-system-manifest-srs-§3-5-§3-8-§3-9" aria-label="Permalink to &quot;Plugin system &amp; manifest (SRS §3.5, §3.8, §3.9)&quot;">​</a></h2><p>Each plugin ships a strict <code>manifest.json</code> (validated at build — invalid manifest fails the build) and an <code>app/</code> tree. The generate step composes <code>app/</code> into the runtime under the manifest&#39;s <code>routePrefix</code> as <strong>copies</strong> (not symlinks; Next&#39;s dev route watcher doesn&#39;t follow symlinked route dirs), git-ignored, with <code>plugins/&lt;id&gt;/</code> as the source of truth. The SDK (<code>@sovereignfs/sdk</code>) is the only plugin↔platform contract, enforced by an ESLint import-boundary rule.</p><p><strong>Shell modes:</strong> <code>default</code> (full chrome sidebar), <code>overlay</code> (plugin renders as a dialog over the current page, with a full-page fallback on hard navigation — RFC 0001), <code>minimal</code> (chrome-free full-bleed — RFC 0014). Console and Account use <code>overlay</code>; a kiosk plugin can use <code>minimal</code> and is still eligible as the root plugin.</p><p><strong>Plugin compatibility (RFC 0024):</strong> <code>manifest.json</code> carries <code>schemaVersion</code> and optional <code>compatibility.minPlatformVersion</code> / <code>maxPlatformVersion</code>. The generate script rejects incompatible plugins at build; <code>sv plugin add</code> rejects at install; boot disables them and surfaces the reason in Console / <code>/api/admin/health</code>.</p><p><strong>Plugin capabilities (RFC 0022):</strong> plugins declare optional <code>capabilities</code> (a record of kebab-case local names) in <code>manifest.json</code>. The platform auto-namespaces them to <code>&lt;pluginId&gt;:&lt;capName&gt;</code>; those with <code>defaultGrant: &quot;all&quot;</code> are injected into every session by the middleware. Plugin-level enforcement lives inside the plugin via <code>sdk.auth.hasCapability</code>.</p><p><strong>Plugin monetization (RFC 0003):</strong> plugins declare a <code>monetization</code> object (<code>model</code>, <code>tiers</code>, <code>license.publicKey</code>). The middleware paywalls plugin routes for users lacking a valid entitlement and redirects to <code>/paywall/&lt;pluginId&gt;</code>. Operators import signed Ed25519 license tokens into Account → Billing; Console → Entitlements shows all grants. Key generation and signing run client-side in Console with <code>crypto.subtle</code>; private keys can be stored on the instance.</p><p><strong>Plugin-scoped env vars (RFC 0018):</strong> plugins declare an <code>env</code> map in <code>manifest.json</code>; keys are auto-namespaced to <code>SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code> (runtime) or <code>NEXT_PUBLIC_SV_PLUGIN_&lt;SLUG&gt;_&lt;KEY&gt;</code> (build). <code>sdk.env.get(&#39;KEY&#39;)</code> reads only the calling plugin&#39;s own vars.</p><h2 id="database-srs-§3-7" tabindex="-1">Database (SRS §3.7) <a class="header-anchor" href="#database-srs-§3-7" aria-label="Permalink to &quot;Database (SRS §3.7)&quot;">​</a></h2><p>Drizzle ORM, dialect-agnostic: SQLite by default, Postgres via env. The default model shares one schema with <strong>slug-prefixed</strong> plugin tables (<code>tasks_lists</code>). <code>tenant_id</code> is present on user-scoped tables from day one for future multi-tenancy. The platform data layer is <strong>async</strong> (Postgres has no synchronous query), so platform DB reads and <code>sdk.db</code>/<code>sdk.platform</code> return promises.</p><p><strong>Per-plugin isolated databases (RFC 0004):</strong> plugins that set <code>&quot;database&quot;: &quot;isolated&quot;</code> get a dedicated store — <code>data/plugins/&lt;pluginId&gt;.db</code> on SQLite, or a separate <code>plugin_&lt;slug&gt;</code> Postgres schema. Migration runner routes each plugin&#39;s <code>migrations/{sqlite,postgres}/</code> to its own store. <code>sdk.db.getClient()</code> is transparent; <code>sv plugin remove</code> drops the store (opt-out: <code>--keep-data</code>).</p><h2 id="sdk-srs-§3-6" tabindex="-1">SDK (SRS §3.6) <a class="header-anchor" href="#sdk-srs-§3-6" aria-label="Permalink to &quot;SDK (SRS §3.6)&quot;">​</a></h2><p><code>@sovereignfs/sdk</code> exposes:</p><ul><li><strong>Stable (v1 guarantee, NFR-04):</strong> <code>auth</code>, <code>db</code>, <code>mailer</code>, <code>platform</code>.</li><li><strong>Implemented, experimental:</strong> <code>data</code> (cross-plugin data sharing, RFC 0002), <code>activity</code> (activity log, RFC 0005), <code>portability</code> (user data export/import, RFC 0007), <code>env</code> (plugin-scoped env vars, RFC 0018), <code>notifications</code> (in-app notification delivery, RFC 0015).</li><li><strong>Reserved (throw <code>NotImplementedError</code> until their backing mechanisms ship):</strong><code>storage</code>, <code>events</code>, <code>billing</code> (stub only; full payment flow is post-v1, Task 1.0.2).</li></ul><p>The package is published to npm with zero runtime dependencies — implementations are host-provided by the runtime at startup via <code>provideHost()</code>, so plugins can type-check and lint in isolation without a full platform checkout. <code>DrizzleClient</code> is kept opaque so the published SDK takes no dialect dependency.</p><h2 id="notifications-web-push-rfc-0015-rfc-0016" tabindex="-1">Notifications &amp; Web Push (RFC 0015, RFC 0016) <a class="header-anchor" href="#notifications-web-push-rfc-0015-rfc-0016" aria-label="Permalink to &quot;Notifications &amp; Web Push (RFC 0015, RFC 0016)&quot;">​</a></h2><p>A per-user <code>notifications</code> table stores in-app inbox items. <code>sdk.notifications.send()</code> is the plugin-facing send surface; the runtime fans out to the inbox, fires toasts for active sessions (polled every 30 s, or via SSE), and optionally delivers Web Push (background, when VAPID keys are configured). Console admins can broadcast announcements to all users or a subset, rate-limited to once per 60 s. Users control per-category muting and push opt-in in Account → Notifications. Push subscriptions are pruned automatically on <code>410 Gone</code>.</p><h2 id="activity-log-srs-§3-14-rfc-0005" tabindex="-1">Activity log (SRS §3.14, RFC 0005) <a class="header-anchor" href="#activity-log-srs-§3-14-rfc-0005" aria-label="Permalink to &quot;Activity log (SRS §3.14, RFC 0005)&quot;">​</a></h2><p>The <code>activity_log</code> table records platform and plugin actions. <code>sdk.activity.log()</code> is fire-and-forget; the runtime stamps actor, plugin, and tenant from request headers. Personal activity appears in Account → Activity; platform-wide history (with actor/action/scope filters) in Console → Activity. Login capture is deferred (Edge middleware cannot write the platform DB).</p><h2 id="cross-plugin-data-sharing-srs-§3-13-rfc-0002" tabindex="-1">Cross-plugin data sharing (SRS §3.13, RFC 0002) <a class="header-anchor" href="#cross-plugin-data-sharing-srs-§3-13-rfc-0002" aria-label="Permalink to &quot;Cross-plugin data sharing (SRS §3.13, RFC 0002)&quot;">​</a></h2><p>A consent-gated, pull-based, read-only sharing mechanism. Provider plugins call <code>sdk.data.provide(contract, resolver)</code>; consumer plugins call <code>sdk.data.query(ref, params)</code> — the runtime checks consent grants in the <code>consent_grants</code> table and logs access to <code>data_access_log</code>. Users manage (and revoke) grants in Account → Data.</p><h2 id="user-data-portability-srs-§3-16-rfc-0007" tabindex="-1">User data portability (SRS §3.16, RFC 0007) <a class="header-anchor" href="#user-data-portability-srs-§3-16-rfc-0007" aria-label="Permalink to &quot;User data portability (SRS §3.16, RFC 0007)&quot;">​</a></h2><p><code>GET /api/account/export</code> streams a versioned ZIP; <code>POST /api/account/import</code> applies it additively with ID remapping. Plugin participation is opt-in via <code>sdk.portability.provideExport</code> / <code>provideImport</code> and the <code>data:export</code> / <code>data:import</code> manifest permissions. Import remaps IDs (no FK breakage) and skips unknown or non-permitted plugin sections with a per-section warning.</p><h2 id="white-labeling-phase-1-rfc-0027-rfc-0032" tabindex="-1">White-labeling, Phase 1 (RFC 0027, RFC 0032) <a class="header-anchor" href="#white-labeling-phase-1-rfc-0027-rfc-0032" aria-label="Permalink to &quot;White-labeling, Phase 1 (RFC 0027, RFC 0032)&quot;">​</a></h2><p>Operators can replace Sovereign&#39;s visual identity via Console → Settings → Branding. The <code>instance_config</code> table stores instance name, primary colour (hex), logo and favicon URLs. <code>InstanceProvider</code> (server component in <code>runtime/src/instance-provider.tsx</code>) reads this at render time, injects <code>--sv-instance-*</code> CSS custom properties at <code>:root</code>, and derives <code>--sv-color-accent</code> from the primary colour. <code>INSTANCE_*</code> env vars supply deployment-level defaults. <code>sdk.platform.getConfig()</code> exposes <code>instanceName</code>, <code>instancePrimaryColor</code>, and the stable <code>instanceId</code> UUID. Phases 2 (branded email + auth login page) and 3 (dynamic PWA manifest) are post-v1.</p><h2 id="pwa-srs-§3-11" tabindex="-1">PWA (SRS §3.11) <a class="header-anchor" href="#pwa-srs-§3-11" aria-label="Permalink to &quot;PWA (SRS §3.11)&quot;">​</a></h2><p>The runtime is an installable PWA. The web manifest and icons are committed source; the service worker is generated at build and disabled in dev. An <code>OfflineBanner</code> client component surfaces soft-offline state (network dropped while the user is on a page); the <code>/offline</code> route covers the hard-offline navigation fallback.</p><h2 id="security-srs-§3-17-rfc-0008" tabindex="-1">Security (SRS §3.17, RFC 0008) <a class="header-anchor" href="#security-srs-§3-17-rfc-0008" aria-label="Permalink to &quot;Security (SRS §3.17, RFC 0008)&quot;">​</a></h2><p>v1 ships the hardening tiers: static security headers + HSTS (production) via each app&#39;s <code>next.config.ts</code>, and a <strong>strict, nonce-based Content-Security-Policy</strong> set per-request in middleware (no <code>&#39;unsafe-inline&#39;</code> for scripts). Postgres connects over TLS from the connection string&#39;s <code>sslmode</code>. Sovereign sends <strong>no telemetry</strong>. Threat model and a self-hoster hardening checklist live in <a href="./security.html">security.md</a>. At-rest, field-level, and zero-knowledge encryption (Tiers 2–4) are specified but post-v1 (Task 1.0.1).</p><h2 id="post-v1-specified-not-built" tabindex="-1">Post-v1 (specified, not built) <a class="header-anchor" href="#post-v1-specified-not-built" aria-label="Permalink to &quot;Post-v1 (specified, not built)&quot;">​</a></h2><p>Native mobile via a Capacitor shell + <code>sdk.device.*</code> (SRS §3.12), and at-rest / field-level / zero-knowledge encryption (SRS §3.17 Tiers 2–4, RFC 0008) are designed but out of scope for v1. White-labeling Phases 2–3 (branded email + auth login page + dynamic PWA manifest) are also deferred (Tasks 1.0.04–1.0.05).</p><h2 id="design-proposals-rfcs" tabindex="-1">Design proposals (RFCs) <a class="header-anchor" href="#design-proposals-rfcs" aria-label="Permalink to &quot;Design proposals (RFCs)&quot;">​</a></h2><p>Cross-cutting design decisions are recorded as RFCs in <a href="./rfcs/README.html"><code>docs/rfcs/</code></a>. See the <a href="./rfcs/README.html">RFC index</a> for the status of each at a glance.</p><h2 id="repository-layout" tabindex="-1">Repository layout <a class="header-anchor" href="#repository-layout" aria-label="Permalink to &quot;Repository layout&quot;">​</a></h2><p>See the monorepo structure in the <a href="https://github.com/sovereignfs/sovereign#monorepo-layout" target="_blank" rel="noreferrer">README</a>.</p>`,52)])])}const g=o(i,[["render",r]]);export{h as __pageData,g as default};
